export const Container = styled(SafeAreaView).attrs<ContainerProps>(() => ({
  edges: ['top', 'left', 'right'] as const,
}))<ContainerProps>`
  flex: 1;

  ${({ theme, bgColor }) => css`
    background: ${theme.colors[bgColor]};
  `}
`;

export const Overlay = styled.View`
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background-color: rgba(0, 0, 0, 0.6);
  z-index: 10;
  pointer-events: auto;
`;

